### Lazy-Compiled Regex Patterns
```rust
use once_cell::sync::Lazy;
use regex::Regex;

/// Pre-compiled regex patterns for tweet content styling
static HASHTAG_REGEX: Lazy<Regex> = Lazy::new(|| {
    Regex::new(r"#\w+").expect("Invalid hashtag regex")
});

static MENTION_REGEX: Lazy<Regex> = Lazy::new(|| {
    Regex::new(r"@\w+").expect("Invalid mention regex")
});

static URL_REGEX: Lazy<Regex> = Lazy::new(|| {
    Regex::new(r"https?://\S+").expect("Invalid URL regex")
});
