### Tweet Card Structure
```rust
use rich_rust::prelude::*;

pub struct TweetCard<'a> {
    tweet: &'a Tweet,
    theme: &'a Theme,
    show_engagement: bool,
    show_media: bool,
    highlight_terms: Vec<String>,
    compact: bool,
}

impl<'a> TweetCard<'a> {
    pub fn new(tweet: &'a Tweet, theme: &'a Theme) -> Self {
        Self {
            tweet,
            theme,
            show_engagement: true,
            show_media: true,
            highlight_terms: vec![],
            compact: false,
        }
    }

    pub fn show_engagement(mut self, show: bool) -> Self {
        self.show_engagement = show;
        self
    }

    pub fn show_media(mut self, show: bool) -> Self {
        self.show_media = show;
        self
    }

    pub fn highlight_terms(mut self, terms: Vec<String>) -> Self {
        self.highlight_terms = terms;
        self
    }

    pub fn compact(mut self, compact: bool) -> Self {
        self.compact = compact;
        self
    }

    pub fn render(&self, output: &Output, width: usize) {
        if !output.is_styled() {
            self.render_plain(output);
            return;
        }

        let mut content = String::new();

        // Header: username and timestamp
        content.push_str(&self.render_header());
        content.push('\n');

        // Tweet text with highlights
        content.push_str(&self.render_content());

        // Engagement metrics
        if self.show_engagement && self.has_engagement() {
            content.push_str("\n\n");
            content.push_str(&self.render_engagement());
        }

        // Media indicators
        if self.show_media && self.tweet.has_media() {
            content.push_str("\n");
            content.push_str(&self.render_media());
        }

        let panel = Panel::from_text(&content)
            .border_style(self.theme.border)
            .padding(Padding::horizontal(1));

        output.print_renderable(&panel);
    }

    fn has_engagement(&self) -> bool {
        self.tweet.favorite_count > 0 
            || self.tweet.retweet_count > 0 
            || self.tweet.reply_count > 0
    }

    fn render_header(&self) -> String {
        let username = format!("[{}]@{}[/]", self.theme.username, self.tweet.username);
        let timestamp = format!("[{}]{}[/]", self.theme.timestamp, 
            self.tweet.created_at.format("%Y-%m-%d %H:%M"));

        let mut indicators = Vec::new();

        if self.tweet.is_reply {
            indicators.push(format!("[{}]↩ Reply[/]", self.theme.muted));
        }

        if self.tweet.is_retweet {
            indicators.push(format!("[{}]🔁 RT[/]", self.theme.muted));
        }

        if self.tweet.is_quote {
            indicators.push(format!("[{}]💬 Quote[/]", self.theme.muted));
        }

        let indicator_str = if indicators.is_empty() {
            String::new()
        } else {
            format!(" {}", indicators.join(" "))
        };

        format!("{} • {}{}", username, timestamp, indicator_str)
    }

    fn render_content(&self) -> String {
        let mut text = self.tweet.full_text.clone();

        // Apply search term highlighting first (takes precedence)
        for term in &self.highlight_terms {
            if let Ok(pattern) = Regex::new(&format!(r"(?i)\b{}\b", regex::escape(term))) {
                text = pattern.replace_all(&text, &format!(
                    "[bold {}]$0[/]", self.theme.highlight
                )).into_owned();
            }
        }

        // Style hashtags (using pre-compiled regex)
        text = HASHTAG_REGEX.replace_all(&text, &format!(
            "[{}]$0[/]", self.theme.hashtag
        )).into_owned();

        // Style mentions
        text = MENTION_REGEX.replace_all(&text, &format!(
            "[{}]$0[/]", self.theme.mention
        )).into_owned();

        // Style URLs
        text = URL_REGEX.replace_all(&text, &format!(
            "[{} underline]$0[/]", self.theme.link
        )).into_owned();

        text
    }

    fn render_engagement(&self) -> String {
        let mut parts = Vec::new();

        if self.tweet.favorite_count > 0 {
            parts.push(format!("[{}]♥[/] {}", self.theme.error, self.tweet.favorite_count));
        }

        if self.tweet.retweet_count > 0 {
            parts.push(format!("[{}]🔁[/] {}", self.theme.success, self.tweet.retweet_count));
        }

        if self.tweet.reply_count > 0 {
            parts.push(format!("[{}]💬[/] {}", self.theme.info, self.tweet.reply_count));
        }

        parts.join(" | ")
    }

    fn render_media(&self) -> String {
        let media_types: Vec<_> = self.tweet.media.iter()
            .map(|m| m.media_type.as_str())
            .collect();
        let media_list = media_types.join(", ");
        format!("[{}]📎 {}[/]", self.theme.muted, media_list)
    }

    fn render_plain(&self, _output: &Output) {
        println!("@{} | {}", self.tweet.username, self.tweet.created_at.format("%Y-%m-%d %H:%M"));

        // Show indicators on separate line if present
        let mut indicators = Vec::new();
        if self.tweet.is_reply { indicators.push("Reply"); }
        if self.tweet.is_retweet { indicators.push("RT"); }
        if self.tweet.is_quote { indicators.push("Quote"); }
        if !indicators.is_empty() {
            println!("[{}]", indicators.join(", "));
        }

        println!("{}", self.tweet.full_text);

        if self.show_engagement && self.has_engagement() {
            let mut parts = Vec::new();
            if self.tweet.favorite_count > 0 {
                parts.push(format!("♥ {}", self.tweet.favorite_count));
            }
            if self.tweet.retweet_count > 0 {
                parts.push(format!("🔁 {}", self.tweet.retweet_count));
            }
            if self.tweet.reply_count > 0 {
                parts.push(format!("💬 {}", self.tweet.reply_count));
            }
            println!("{}", parts.join(" | "));
        }

        println!("---");
    }
}
```

### Quote Tweet Display
```rust
pub struct QuoteTweetCard<'a> {
    tweet: &'a Tweet,
    quoted: &'a Tweet,
    theme: &'a Theme,
    highlight_terms: Vec<String>,
}

impl<'a> QuoteTweetCard<'a> {
    pub fn new(tweet: &'a Tweet, quoted: &'a Tweet, theme: &'a Theme) -> Self {
        Self {
            tweet,
            quoted,
            theme,
            highlight_terms: vec![],
        }
    }

    pub fn highlight_terms(mut self, terms: Vec<String>) -> Self {
        self.highlight_terms = terms;
        self
    }

    pub fn render(&self, output: &Output) {
        // Render main tweet
        TweetCard::new(self.tweet, self.theme)
            .highlight_terms(self.highlight_terms.clone())
            .render(output, output.width());

        // Render quoted tweet indented
        if output.is_styled() {
            output.print(&format!("[{}]┗━ Quoted:[/]", self.theme.muted));
        } else {
            println!("  > Quoted:");
        }

        TweetCard::new(self.quoted, self.theme)
            .highlight_terms(self.highlight_terms.clone())
            .compact(true)
            .render(output, output.width().saturating_sub(4));
    }
}
