#!/bin/bash
set -euo pipefail
LOG=/tmp/xf-tweet-card-e2e.log
echo "[$(date -Iseconds)] Starting Tweet Card E2E tests" | tee $LOG

# Test 1: Search results show tweet cards
echo "Test 1: Tweet card display" | tee -a $LOG
OUTPUT=$(xf search "test" --doc-type tweets --limit 3 2>&1)
echo "$OUTPUT" | head -30 | tee -a $LOG
if [ -n "$OUTPUT" ]; then
    echo "  PASS: Tweet results displayed" | tee -a $LOG
else
    echo "  WARN: No tweet results (may be expected)" | tee -a $LOG
fi

# Test 2: Hashtags visible
echo "Test 2: Hashtag display" | tee -a $LOG
OUTPUT=$(xf search "#" --doc-type tweets --limit 1 2>&1)
echo "$OUTPUT" | head -10 | tee -a $LOG

# Test 3: Mentions visible
echo "Test 3: Mention display" | tee -a $LOG
OUTPUT=$(xf search "@" --doc-type tweets --limit 1 2>&1)
echo "$OUTPUT" | head -10 | tee -a $LOG

# Test 4: Engagement metrics shown
echo "Test 4: Engagement metrics" | tee -a $LOG
if echo "$OUTPUT" | grep -qE '♥|🔁|💬|[0-9]+ like|[0-9]+ retweet'; then
    echo "  PASS: Engagement metrics visible" | tee -a $LOG
else
    echo "  INFO: Engagement may not be in all displays" | tee -a $LOG
fi

# Test 5: Piped output clean
echo "Test 5: Piped output" | tee -a $LOG
PIPED=$(xf search "test" --doc-type tweets --limit 1 2>&1 | cat)
if echo "$PIPED" | grep -qP '\x1b\['; then
    echo "  FAIL: ANSI in piped output" | tee -a $LOG
    exit 1
fi
echo "  PASS: Piped output clean" | tee -a $LOG

echo "[$(date -Iseconds)] All Tweet Card tests passed" | tee -a $LOG
