### 2. Embedding Quality Tests
```rust
#[test]
fn test_similar_texts_have_high_similarity() {
    let embedder = static_mrl_embedder();
    let e1 = embedder.embed("great coffee shop downtown").unwrap();
    let e2 = embedder.embed("best cafe in the city center").unwrap();
    let e3 = embedder.embed("quantum physics experiments").unwrap();

    let sim_related = cosine_similarity(&e1, &e2);
    let sim_unrelated = cosine_similarity(&e1, &e3);

    tracing::info!(
        related = sim_related,
        unrelated = sim_unrelated,
        margin = sim_related - sim_unrelated,
        "Quality test: coffee/cafe vs physics"
    );

    assert!(sim_related > sim_unrelated,
        "Related texts should be more similar: {} vs {}", sim_related, sim_unrelated);
    assert!(sim_related > 0.4, "Related texts should have >0.4 similarity, got {}", sim_related);
    assert!(sim_unrelated < 0.6, "Unrelated texts should have <0.6 similarity, got {}", sim_unrelated);
}

#[test]
fn test_model2vec_quality() {
    let embedder = model2vec_embedder();
    let q = embedder.embed("programming languages").unwrap();
    let d_good = embedder.embed("software development coding").unwrap();
    let d_bad = embedder.embed("tropical fish aquarium care").unwrap();

    let sim_good = cosine_similarity(&q, &d_good);
    let sim_bad = cosine_similarity(&q, &d_bad);

    tracing::info!(
        model = "Model2Vec",
        sim_relevant = sim_good,
        sim_irrelevant = sim_bad,
        "Quality test"
    );

    assert!(sim_good > sim_bad,
        "Model2Vec should rank relevant higher: {} vs {}", sim_good, sim_bad);
