use clap_complete::{generate, Generator};
use clap_complete::shells::{Bash as BashGen, Zsh as ZshGen, Fish as FishGen, PowerShell as PsGen, Elvish as ElvGen};

/// Generate shell completions for the CLI
pub fn generate_completions(shell: Shell, output: &Output) -> Result<()> {
    let mut cmd = build_cli(); // Get the clap Command

    // Generate completions to stdout
    match shell {
        Shell::Bash => generate_to_stdout::<BashGen>(&mut cmd),
        Shell::Zsh => generate_to_stdout::<ZshGen>(&mut cmd),
        Shell::Fish => generate_to_stdout::<FishGen>(&mut cmd),
        Shell::PowerShell => generate_to_stdout::<PsGen>(&mut cmd),
        Shell::Elvish => generate_to_stdout::<ElvGen>(&mut cmd),
    }

    // Show installation instructions on stderr (so they don't interfere with piping)
    show_install_instructions(shell, output);

    Ok(())
}

fn generate_to_stdout<G: Generator>(cmd: &mut clap::Command) {
    generate(G::default(), cmd, "xf", &mut std::io::stdout());
}

fn show_install_instructions(shell: Shell, output: &Output) {
    let instructions = shell.install_instructions();

    if output.is_styled() {
        let panel = Panel::from_text(&format!(
            "[{}]Installation Instructions for {}[/]\n\n{}",
            output.theme.heading,
            shell.as_str(),
            instructions
        ))
        .title("Shell Completions");
        eprintln!(); // Blank line before panel
        // Print to stderr so it doesn't interfere with completion output
        output.eprint_renderable(&panel);
    } else {
        eprintln!();
        eprintln!("# Installation Instructions for {}", shell.as_str());
        eprintln!("{}", instructions);
    }
}
